// A/B the over-the-air tone at the ACTUAL detected tone bin (not a fixed guess).
import { readFileSync } from 'node:fs';
const FS = 2_048_000, N = 1 << 16, DC_GUARD_HZ = 20_000;

function spectrum(path) {
  const u8 = readFileSync(path);
  const re = new Float64Array(N), im = new Float64Array(N);
  for (let k = 0; k < N; k++) {
    const w = 0.5 - 0.5 * Math.cos((2 * Math.PI * k) / (N - 1));
    re[k] = ((u8[2*k] - 128) / 128) * w;
    im[k] = ((u8[2*k+1] - 128) / 128) * w;
  }
  for (let i = 1, j = 0; i < N; i++) { let b = N>>1; for (; j&b; b>>=1) j^=b; j^=b;
    if (i<j){[re[i],re[j]]=[re[j],re[i]];[im[i],im[j]]=[im[j],im[i]];} }
  for (let len = 2; len <= N; len <<= 1) { const ang=-2*Math.PI/len, wr=Math.cos(ang), wi=Math.sin(ang);
    for (let i=0;i<N;i+=len){ let cr=1,ci=0; for(let k=0;k<len/2;k++){ const a=i+k,b=i+k+len/2;
      const tr=re[b]*cr-im[b]*ci, ti=re[b]*ci+im[b]*cr; re[b]=re[a]-tr; im[b]=im[a]-ti; re[a]+=tr; im[a]+=ti;
      const nr=cr*wr-ci*wi; ci=cr*wi+ci*wr; cr=nr; } } }
  const mag = new Float64Array(N);
  for (let k=0;k<N;k++) mag[k]=Math.hypot(re[k],im[k]);
  return mag;
}
const binToHz = (k) => (k < N/2 ? k : k - N) * (FS / N);
const hzToBin = (hz) => Math.round((hz/FS)*N) & (N-1);
function floorOf(mag, exclK){ let s=0,c=0; for(let k=0;k<N;k++){ const hz=binToHz(k);
  if(Math.abs(hz)<DC_GUARD_HZ) continue; if(Math.abs(((k-exclK+N)%N))<8) continue; s+=mag[k]; c++; } return s/c; }

const on = spectrum(process.argv[2]);
const off = spectrum(process.argv[3]);

// detect tone bin from ON (exclude DC)
let pk=-1,pm=-1; for(let k=0;k<N;k++){ if(Math.abs(binToHz(k))<DC_GUARD_HZ) continue; if(on[k]>pm){pm=on[k];pk=k;} }
const toneHz = binToHz(pk);
// peak magnitude in a +-3 bin neighborhood (window leakage) for each
const nbhd = (mag) => { let m=0; for(let d=-3;d<=3;d++) m=Math.max(m,mag[(pk+d+N)%N]); return m; };
const onTone = nbhd(on), offTone = nbhd(off);
// does OFF have ANY peak within +-5kHz of the tone?
let offNear=0; const lo=hzToBin(toneHz-5000), hi=hzToBin(toneHz+5000);
for(let k=Math.min(lo,hi);k<=Math.max(lo,hi);k++) offNear=Math.max(offNear, off[(k+N)%N]);

const db=(a,b)=>20*Math.log10(a/b);
console.log(JSON.stringify({ overTheAirAB: {
  detectedToneHz: Math.round(toneHz),
  recoveredBroadcastSymbol: Math.round(Math.abs(toneHz)/1000),
  expectedBroadcastSymbol: 66,
  toneBin: pk,
  txOn:  { magAtTone:+onTone.toFixed(2),  snr_dB:+db(onTone, floorOf(on,pk)).toFixed(2) },
  txOff: { magAtTone:+offTone.toFixed(2), snr_dB:+db(offTone, floorOf(off,pk)).toFixed(2),
           maxWithin5kHz:+offNear.toFixed(2) },
  toneOnVsOff_dB: +db(onTone, offTone).toFixed(2),
  match: Math.round(Math.abs(toneHz)/1000) === 66,
}}, null, 2));
